--
-- Name: get_ultimo_cierre(integer, date); Type: FUNCTION; Schema: public; Owner: ricoh_admin
--

CREATE FUNCTION public.get_ultimo_cierre(p_printer_id integer, p_fecha date) RETURNS TABLE(id integer, fecha_inicio date, fecha_fin date, total_paginas integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        c.id,
        c.fecha_inicio,
        c.fecha_fin,
        c.total_paginas
    FROM cierres_mensuales c
    WHERE c.printer_id = p_printer_id
      AND c.fecha_fin < p_fecha
    ORDER BY c.fecha_fin DESC
    LIMIT 1;
END;
$$;


ALTER FUNCTION public.get_ultimo_cierre(p_printer_id integer, p_fecha date) OWNER TO ricoh_admin;

