--
-- Name: v_cierres_resumen; Type: VIEW; Schema: public; Owner: ricoh_admin
--

CREATE VIEW public.v_cierres_resumen AS
SELECT
    NULL::integer AS id,
    NULL::integer AS printer_id,
    NULL::character varying(255) AS hostname,
    NULL::character varying(45) AS ip_address,
    NULL::character varying(20) AS tipo_periodo,
    NULL::date AS fecha_inicio,
    NULL::date AS fecha_fin,
    NULL::integer AS anio,
    NULL::integer AS mes,
    NULL::integer AS dias_periodo,
    NULL::integer AS total_paginas,
    NULL::integer AS diferencia_total,
    NULL::timestamp with time zone AS fecha_cierre,
    NULL::character varying(100) AS cerrado_por,
    NULL::character varying(64) AS hash_verificacion,
    NULL::bigint AS total_usuarios,
    NULL::bigint AS suma_consumos_usuarios,
    NULL::bigint AS porcentaje_diferencia;


ALTER VIEW public.v_cierres_resumen OWNER TO ricoh_admin;

--
-- Name: VIEW v_cierres_resumen; Type: COMMENT; Schema: public; Owner: ricoh_admin
--

COMMENT ON VIEW public.v_cierres_resumen IS 'Vista resumen de cierres con informaci├│n agregada de usuarios y validaci├│n de integridad';


--
-- Name: v_cierres_usuarios_completo; Type: VIEW; Schema: public; Owner: ricoh_admin
--

CREATE VIEW public.v_cierres_usuarios_completo AS
 SELECT cmu.id,
    cmu.cierre_mensual_id,
    cmu.total_paginas,
    cmu.total_bn,
    cmu.total_color,
    cmu.copiadora_bn,
    cmu.copiadora_color,
    cmu.impresora_bn,
    cmu.impresora_color,
    cmu.escaner_bn,
    cmu.escaner_color,
    cmu.fax_bn,
    cmu.consumo_total,
    cmu.consumo_copiadora,
    cmu.consumo_impresora,
    cmu.consumo_escaner,
    cmu.consumo_fax,
    cmu.created_at,
    cmu.user_id,
    u.codigo_de_usuario AS codigo_usuario,
    u.name AS nombre_usuario,
    u.smb_path,
    u.centro_costos
   FROM (public.cierres_mensuales_usuarios cmu
     JOIN public.users u ON ((cmu.user_id = u.id)));


ALTER VIEW public.v_cierres_usuarios_completo OWNER TO ricoh_admin;

--
-- Name: v_contadores_usuario_completo; Type: VIEW; Schema: public; Owner: ricoh_admin
--

CREATE VIEW public.v_contadores_usuario_completo AS
 SELECT cu.id,
    cu.printer_id,
    cu.total_paginas,
    cu.total_bn,
    cu.total_color,
    cu.copiadora_bn,
    cu.copiadora_mono_color,
    cu.copiadora_dos_colores,
    cu.copiadora_todo_color,
    cu.copiadora_hojas_2_caras,
    cu.copiadora_paginas_combinadas,
    cu.impresora_bn,
    cu.impresora_mono_color,
    cu.impresora_dos_colores,
    cu.impresora_color,
    cu.impresora_hojas_2_caras,
    cu.impresora_paginas_combinadas,
    cu.escaner_bn,
    cu.escaner_todo_color,
    cu.fax_bn,
    cu.fax_paginas_transmitidas,
    cu.revelado_negro,
    cu.revelado_color_ymc,
    cu.eco_uso_2_caras,
    cu.eco_uso_combinar,
    cu.eco_reduccion_papel,
    cu.tipo_contador,
    cu.fecha_lectura,
    cu.created_at,
    cu.user_id,
    u.codigo_de_usuario AS codigo_usuario,
    u.name AS nombre_usuario,
    u.smb_path,
    u.centro_costos
   FROM (public.contadores_usuario cu
     JOIN public.users u ON ((cu.user_id = u.id)));


ALTER VIEW public.v_contadores_usuario_completo OWNER TO ricoh_admin;

--
-- Name: v_printers_completo; Type: VIEW; Schema: public; Owner: ricoh_admin
--

CREATE VIEW public.v_printers_completo AS
 SELECT id,
    hostname,
    ip_address,
    location,
    empresa_id,
    status,
    detected_model,
    serial_number,
    has_color,
    has_scanner,
    has_fax,
    tiene_contador_usuario,
    usar_contador_ecologico,
    formato_contadores,
    capabilities_json,
    inconsistency_count,
    toner_cyan,
    toner_magenta,
    toner_yellow,
    toner_black,
    last_seen,
    notes,
    created_at,
    updated_at,
    ((capabilities_json ->> 'has_color'::text))::boolean AS cap_has_color,
    ((capabilities_json ->> 'has_scanner'::text))::boolean AS cap_has_scanner,
    ((capabilities_json ->> 'has_fax'::text))::boolean AS cap_has_fax,
    ((capabilities_json ->> 'has_duplex'::text))::boolean AS cap_has_duplex
   FROM public.printers p;


ALTER VIEW public.v_printers_completo OWNER TO ricoh_admin;

--
-- Name: v_users_completo; Type: VIEW; Schema: public; Owner: ricoh_admin
--

CREATE VIEW public.v_users_completo AS
 SELECT u.id,
    u.name,
    u.codigo_de_usuario,
    s.server_address AS smb_server,
    s.port AS smb_port,
    u.smb_path,
    nc.username AS network_username,
    u.func_copier,
    u.func_copier_color,
    u.func_printer,
    u.func_printer_color,
    u.func_document_server,
    u.func_fax,
    u.func_scanner,
    u.func_browser,
    u.empresa_id,
    u.centro_costos,
    u.is_active,
    u.created_at,
    u.updated_at
   FROM ((public.users u
     JOIN public.smb_servers s ON ((u.smb_server_id = s.id)))
     JOIN public.network_credentials nc ON ((u.network_credential_id = nc.id)));


ALTER VIEW public.v_users_completo OWNER TO ricoh_admin;

