--
-- Name: v_cierres_resumen _RETURN; Type: RULE; Schema: public; Owner: ricoh_admin
--

CREATE OR REPLACE VIEW public.v_cierres_resumen AS
 SELECT c.id,
    c.printer_id,
    p.hostname,
    p.ip_address,
    c.tipo_periodo,
    c.fecha_inicio,
    c.fecha_fin,
    c.anio,
    c.mes,
    ((c.fecha_fin - c.fecha_inicio) + 1) AS dias_periodo,
    c.total_paginas,
    c.diferencia_total,
    c.fecha_cierre,
    c.cerrado_por,
    c.hash_verificacion,
    count(cu.id) AS total_usuarios,
    sum(cu.consumo_total) AS suma_consumos_usuarios,
        CASE
            WHEN (c.diferencia_total > 0) THEN ((abs((sum(cu.consumo_total) - c.diferencia_total)) / c.diferencia_total) * 100)
            ELSE (0)::bigint
        END AS porcentaje_diferencia
   FROM ((public.cierres_mensuales c
     LEFT JOIN public.printers p ON ((c.printer_id = p.id)))
     LEFT JOIN public.cierres_mensuales_usuarios cu ON ((c.id = cu.cierre_mensual_id)))
  GROUP BY c.id, p.hostname, p.ip_address;


